VALUES
  ('optician-moex-00569', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一名正視眼患者，使用推進法（push-up）檢查，推測其單眼調節幅度（amplitudeofaccommodation）為7D， 請問他的調節近點（nearpointofaccommodation）為下列何者？', '["14.29cm", "28.57cm", "40cm", "7.14cm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00570', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列那些立體視覺檢查，患者不需配戴額外輔助眼鏡（偏光鏡或紅綠眼鏡），較適合年齡較小的孩童及無', '["Bernell立體視覺檢查", "Frisby立體視覺檢查", "Lang立體視覺檢查", "Random DotE 立體視覺檢查  ⑤Titmus立體視覺檢查  ⑥TNO立體視覺檢查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00571', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '對病人做遮蓋測試（covertest），雙眼直視未見明顯偏位，遮蓋左眼時可見右眼稍微向外移動，打開左眼時 可見右眼稍微向內移動，遮蓋右眼時可見左眼無移動，打開右眼時可見左眼無移動，病人有下列何種疾病？', '["交替性內斜視", "右眼內隱斜位", "右眼內斜視", "左眼外隱斜位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00572', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於內聚力（convergence）與調節力（accommodation）何者正確？', '["眼睛看近時內聚力增加，內隱斜位不變", "調節力下降，調節性內聚力（accommodativeconvergenceoraccommodativefusionalreserve）下降", "若在眼前持續增加基底朝內稜鏡直到影像模糊，可測得內聚力幅度（amplitudeofconvergence）", "若在眼前持續增加基底朝內稜鏡直到產生複視，可測得調節性內聚力（accommodative convergence or accommodativefusionalreserve）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00573', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '右眼上斜視（hypertropia）個案進行後續的帕克三步驟檢查（ThePark’sthree-stepprocedure），下列何者正確？', '["往右看時，右眼上斜偏位量增加，可能為右上斜肌（rightsuperioroblique）或左上直肌（leftsuperiorrectus） 異常", "往左看時，右眼上斜偏位量增加，可能為右下直肌（rightinferiorrectus）或左下斜肌（leftinferioroblique） 異常", "若右看時，右眼上斜偏位量增加，且頭往右傾時，右眼上斜偏位量增加，為左下斜肌麻痺", "若右看時，右眼上斜偏位量增加，且頭往右傾時，右眼上斜偏位量增加，為右下直肌麻痺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00574', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '患者雙眼視力 20/20，當你遮蓋右眼時，觀察到他的左眼向外移動；右眼去遮蓋時，左眼不動；當你遮蓋 左眼時，右眼向外移動，左眼去遮蓋時，右眼不動，這表示患者有那種異常？', '["交替性外斜視（alternatingexotropia）", "內斜位（esophoria）", "間歇性內斜視（intermittentesophoria）", "交替性內斜視（alternatingesotropia）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00575', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '執行魏氏四點檢查時，患者右眼配戴紅色鏡片、左眼配戴綠色鏡片，於40cm檢查處表示看到四個亮點； 隨後逐漸將視標遠離受試者，於2m處患者表示綠色亮點消失，此時若是遮蔽右眼，綠色亮點會再次出現， 試問此檢查結果該如何記錄？', '["左眼抑制，雙眼注視情況下有中央抑制性暗點", "右眼抑制，雙眼注視情況下有中央抑制性暗點", "在40cm處平面融像，左眼於2m處抑制，雙眼注視情況下有中央抑制暗點", "在40cm處平面融像，左眼於2m處抑制，左眼有單側性中央抑制暗點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00576', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '驗光師採用眼球轉動外部肌肉的測試（配合使用紅色鏡片）主要是檢查以下何種狀況？', '["判斷是否有視神經病變", "判斷是否有固視偏移", "判斷是否有斜位", "判斷視線偏移是否為共動性或非共動性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00577', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於立體視覺測驗，下列敘述何者正確？', '["隨機亂點立體視覺具有最少的單眼線索，為測驗首選", "TNO立體視覺不用配戴試驗眼鏡，適合抗拒配戴眼鏡的幼童實施測試", "立體視覺的單位是分角（minutesofarc）", "立體視覺的測驗距離可依據受測者閱讀習慣與手的長度進行調整，不影響測驗結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00578', 'optician', 'optician-moex-112-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '調節正常患者，兩眼均遠視+2.00D在未矯正狀態下看33cm距離時，須使用多少的調節力？', '["2D", "3D", "5D", "7D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:29+00:00", "source_pdf_sha1": "2f682e76ad4b", "answer_pdf_sha1": "ee9d4e54516d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
